// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>

typedef struct {int l, r, val;} Node;

Node *seg;
int N;

int max(int a, int b){return a>b?a:b;}

void build(int idx, int l, int r, int *a){
    seg[idx].l=l; seg[idx].r=r;
    if(l==r){seg[idx].val=a[l];return;}
    int mid=(l+r)/2;
    build(idx*2,l,mid,a);
    build(idx*2+1,mid+1,r,a);
    seg[idx].val=max(seg[idx*2].val, seg[idx*2+1].val);
}

int query(int idx, int ql, int qr){
    if(ql>seg[idx].r || qr<seg[idx].l) return -1; // -1 works because b_i >=1
    if(ql<=seg[idx].l && seg[idx].r<=qr) return seg[idx].val;
    int left=query(idx*2,ql,qr);
    int right=query(idx*2+1,ql,qr);
    return max(left,right);
}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        scanf("%d",&N);
        int *b = (int*)malloc(N*sizeof(int));
        for(int i=0;i<N;i++) scanf("%d",&b[i]);
        // prefix and suffix max
        int *pref = (int*)malloc(N*sizeof(int));
        int *suff = (int*)malloc(N*sizeof(int));
        for(int i=0;i<N;i++) pref[i]= (i==0)?b[i]: (pref[i-1]>b[i]?pref[i-1]:b[i]);
        for(int i=N-1;i>=0;i--) suff[i]= (i==N-1)?b[i]: (suff[i+1]>b[i]?suff[i+1]:b[i]);
        // segment tree
        seg = (Node*)malloc(sizeof(Node)*4*N);
        build(1,0,N-1,b);
        int Q; scanf("%d",&Q);
        while(Q--){
            int L,R; scanf("%d %d",&L,&R);
            int outside = -1;
            if(L>0) outside = pref[L-1];
            if(R+1<N) outside = (outside> suff[R+1]?outside:suff[R+1]);
            int insideMax = query(1,L,R);
            double ans = outside;
            double halfInside = insideMax/2.0;
            if(halfInside>ans) ans=halfInside;
            printf("%.1f\n",ans);
        }
        free(b); free(pref); free(suff); free(seg);
    }
    return 0;
}
